### Deobfuscated Code

```javascript
// --- Configuration ---
const Math_TWO_PI = 6.283;
const Math_GOLDEN_RATIO = 1.618;
const Math_SQRT1_2 = 0.707;

const config = {
    attraction: 4000,
    repulsionEff: 0.004,
    amplification: 0.92, // Acts as friction/damping
    centralAtt: 0.0003,  // Gravity pulling towards center
    streamMax: 40,       // Max amount of particles
    streamDecay: 0.04,   // Particle slow-down rate
    theta: 0.06          // Camera interpolation speed
};

// --- Entities ---
const nodes = [
    { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

const springs = [
    { a: 'hub',   b: 'alpha',   rest: 160, k: 0.006 },
    { a: 'hub',   b: 'beta',    rest: 160, k: 0.005 },
    { a: 'hub',   b: 'gamma',   rest: 170, k: 0.004 },
    { a: 'hub',   b: 'delta',   rest: 170, k: 0.004 },
    { a: 'hub',   b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
    { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
    { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

let camera = { x: 400, y: 300, zoom: 1 };
let targetCamera = { x: 400, y: 300, zoom: 1 };

let particles = [];
let frameCount = 0;

// --- Helper Functions ---
function getNodeById(id) {
    for (let i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// --- Main Engine Functions ---

// 1. Calculate Graph Physics
function updatePhysics() {
    // Apply Repulsion (N-Body problem: every node repels every other node)
    for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
            let dx = nodes[i].x - nodes[j].x;
            let dy = nodes[i].y - nodes[j].y;
            let dist = Math.sqrt(dx * dx + dy * dy) || 1;

            let force = config.attraction / (dist * dist);
            let fx = (dx / dist) * force;
            let fy = (dy / dist) * force;

            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // Apply Spring Forces (Hooke's Law)
    for (let i = 0; i < springs.length; i++) {
        let nodeA = getNodeById(springs[i].a);
        let nodeB = getNodeById(springs[i].b);
        if (!nodeA || !nodeB) continue;

        let dx = nodeB.x - nodeA.x;
        let dy = nodeB.y - nodeA.y;
        let dist = Math.sqrt(dx * dx + dy * dy) || 1;

        let displacement = dist - springs[i].rest;
        let force = (springs[i].k || config.repulsionEff) * displacement;

        let fx = (dx / dist) * force;
        let fy = (dy / dist) * force;

        nodeA.vx += fx;
        nodeA.vy += fy;
        nodeB.vx -= fx;
        nodeB.vy -= fy;
    }

    // Apply Central Gravity, Friction, and update positions
    for (let i = 0; i < nodes.length; i++) {
        let n = nodes[i];

        // Pull towards center (400, 300)
        n.vx += (400 - n.x) * config.centralAtt;
        n.vy += (300 - n.y) * config.centralAtt;

        // Apply damping (friction)
        n.vx *= config.amplification;
        n.vy *= config.amplification;

        // Update positions based on velocity
        n.x += n.vx;
        n.y += n.vy;
    }
}

// 2. Emit visual particles (sparks/streams)
function emitParticle() {
    if (particles.length >= config.streamMax) return;

    // Pick a random node to emit from
    let sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
    let angle = Math.random() * Math_TWO_PI;
    let speed = 0.3 + (Math.random() * Math_SQRT1_2);

    particles.push({
        x: sourceNode.x,
        y: sourceNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + (Math.random() * 1200),
        size: 0.8 + (Math.random() * Math_GOLDEN_RATIO * Math_SQRT1_2)
    });
}

// 3. Update active particles
function updateParticles() {
    // Iterate backwards to allow safe removal of dead particles
    for (let i = particles.length - 1; i >= 0; i--) {
        let p = particles[i];

        p.age++;
        if (p.age > p.maxAge) {
            particles.splice(i, 1);
            continue;
        }

        // Apply drag/decay to particle velocity
        p.vx *= (1 - (config.streamDecay * 0.125));
        p.vy *= (1 - (config.streamDecay * 0.125));

        // Update position
        p.x += p.vx;
        p.y += p.vy;
    }
}

// 4. Smooth Camera movement
function updateCamera() {
    camera.x += (targetCamera.x - camera.x) * config.theta;
    camera.y += (targetCamera.y - camera.y) * config.theta;
    camera.zoom += (targetCamera.zoom - camera.zoom) * config.theta;
}

// --- Main Loop ---
function mainLoop() {
    updatePhysics();
    updateParticles();
    updateCamera();

    // Emit a new particle every 3 frames
    if (frameCount % 3 === 0) {
        emitParticle();
    }

    frameCount++;
}

// Run the simulation at roughly 100 FPS (10ms intervals)
setInterval(mainLoop, 10);
```

### Explanation: What does this code do?

This code is a underlying math and physics engine for a **2D interactive force-directed graph (network) simulation**. It handles the mathematical calculations behind the scenes, determining where elements should be drawn on an HTML5 Canvas or SVG (though the actual rendering/drawing code is missing from this snippet).

Here is a breakdown of its features:

1. **The Graph Structure:**
   * It creates a central "Hub" node and 5 smaller satellite nodes (Alpha, Beta, Gamma, Delta, Epsilon).
   * It defines a set of "Springs" (edges/links) that connect these nodes together, primarily linking the satellite nodes to the Hub, with a few outer connections between satellites.

2. **The Physics Simulation:**
   * **Mutual Repulsion:** Similar to how magnets of the same polarity repel each other, every node pushes every other node away. This prevents them from overlapping.
   * **Spring Forces:** The links act like physical springs. If two connected nodes move too far apart, the spring pulls them together. If they get too close, the spring pushes them to their "rest" distance.
   * **Central Gravity:** A weak force constantly pulls all nodes toward the center coordinates `(400, 300)` to keep the graph from floating entirely off-screen.
   * **Friction/Damping:** Velocities are multiplied by `0.92` every frame so the nodes eventually settle down instead of bouncing forever.

3. **The Particle System:**
   * Every 3rd frame, it spawns a particle from a randomly chosen node.
   * These particles are given a random trajectory, speed, lifespan, and size.
   * Over time, their speed slows down (decay) and they drift away from the node until they reach their maximum age, at which point they are deleted. (This is usually used to render a glowing "spark", "dust", or "data stream" effect).

4. **The Camera:**
   * It includes a logic object for a camera/viewport that smoothly glides towards a target position and zoom level using Linear Interpolation (Lerp). 

**In short:** If you plugged a rendering function into this, you would see a floating, bouncy web of 6 labeled circles connected by lines, with little specs of dust/sparks continuously shooting out of them, all slowly settling into a stable web shape in the center of the screen.
